mapper.select:
SELECT id, user_id as userId, name, phone, province, city, district, detail_address as detail, is_default as isDefault, created_at as createdAt, updated_at as updatedAt
FROM user_address
WHERE id = #{id}

mapper.update:
UPDATE user_address
SET name = #{name}, phone = #{phone}, province = #{province}, city = #{city}, district = #{district}, 
    detail_address = #{detail}, is_default = #{isDefault}, updated_at = #{updatedAt}
WHERE id = #{id}

UPDATE user_address
SET is_default = 0
WHERE user_id = #{userId}

UPDATE user_address
SET is_default = 1
WHERE id = #{id}
